class Solution {
    public List<Integer> sequentialDigits(int low, int high) {
        List<Integer> result = new ArrayList<>();
        for (int length = String.valueOf(low).length(); length <= String.valueOf(high).length(); length++) {
            for (int start = 1; start <= 10 - length; start++) {
                int num = generateNumber(start, length);
                if (num >= low && num <= high) {
                    result.add(num);
                }
            }
        }
        return result;
    }

    private int generateNumber(int start, int length) {
        int num = 0;
        for (int i = 0; i < length; i++) {
            num = num * 10 + start + i;
        }
        return num;
    }
}
